import request from 'supertest';
import app from '../src/app';

describe('GET /', () => {
  it('responds with HTML containing Hello World', async () => {
    const res = await request(app).get('/');
    expect(res.status).toBe(200);
    expect(res.text).toContain('Hello World');
  });
});

